      fill="#6C707E"
    />
    <path d="M7.5 11h1v3.5a.5.5 0 0 1-1 0z" fill="#6C707E" />
  </svg>
);

const PinDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M6.482 5.707 6.268 7.2c-.07.488-.366.872-.73 1.093C4.785 8.748 4.398 9.414 4.2 10h7.603c-.2-.586-.587-1.253-1.338-1.707A1.54 1.54 0 0 1 9.734 7.2L9.52 5.707A1.496 1.496 0 0 1 11.001 4V3h-6v1c.91 0 1.61.806 1.48 1.707M5.278 7.06a.54.54 0 0 1-.258.378c-1.17.708-1.661 1.79-1.868 2.577-.141.534.297.986.849.986h8c.552 0 .99-.452.85-.986-.208-.786-.7-1.87-1.869-2.577a.54.54 0 0 1-.258-.378l-.214-1.493A.496.496 0 0 1 11.001 5a1 1 0 0 0 1-1V3a1 1 0 0 0-1-1h-6a1 1 0 0 0-1 1v1a1 1 0 0 0 1 1c.302 0 .533.267.49.566z"
      fill="#CED0D6"
    />
    <path d="M7.5 11h1v3.5a.5.5 0 0 1-1 0z" fill="#CED0D6" />
  </svg>
);

export const Pin: FC<PinProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? PinLight : PinDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
